from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    sentence = ""
    for i, triple in enumerate(triples):
        if i == 0:
            sentence += f"{triple.subject} has a {triple.predicate} of {triple.object}"
        else:
            sentence += f", and a {triple.predicate} of {triple.object}"
    return sentence + "."

